class Solution(object):
    def distributeCookies(self, cookies, k):
        n = len(cookies)
        min_unfairness = float('inf')
        children = [0] * k
        def backtrack(i):
            nonlocal min_unfairness
            if i == n:
                min_unfairness = min(min_unfairness, max(children))
                return
            for j in range(k):
                children[j] += cookies[i]
                backtrack(i + 1)
                children[j] -= cookies[i]
        backtrack(0)
        return min_unfairness
